#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int* findLargestDivisibleSubset(int* nums, int numsSize) {
    qsort(nums, numsSize, sizeof(int), compare);
    int* dp = (int*)malloc(numsSize * sizeof(int));
    int* prev = (int*)malloc(numsSize * sizeof(int));
    for (int i = 0; i < numsSize; i++) {
        dp[i] = 1;
        prev[i] = -1;
    }
    int maxLen = 1;
    int maxIdx = 0;
    for (int i = 1; i < numsSize; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[i] % nums[j] == 0 && dp[i] < dp[j] + 1) {
                dp[i] = dp[j] + 1;
                prev[i] = j;
            }
        }
        if (dp[i] > maxLen) {
            maxLen = dp[i];
            maxIdx = i;
        }
    }
    int* subset = (int*)malloc(maxLen * sizeof(int));
    int idx = maxIdx;
    for (int i = maxLen - 1; i >= 0; i--) {
        subset[i] = nums[idx];
        idx = prev[idx];
    }
    free(dp);
    free(prev);
    return subset;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        int* nums = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &nums[i]);
        }
        int* subset = findLargestDivisibleSubset(nums, N);
        for (int i = 0; i < maxLen; i++) {
            printf("%d ", subset[i]);
        }
        printf("\n");
        free(nums);
        free(subset);
    }
    return 0;
}

